DriveAudio:
    ; PATCHED: NOP — audio data requires NES bank mapping not yet implemented.
    rts
    ; If the game is paused, then silence all channels
    ; by first disabling them, then enabling them.
    ;
    ; Then go drive tune channel 0 only.
    ;
    move.b  ($00E0,A4),D0
    beq  _L_z00_DriveAudio_Play
    moveq   #0,D0
    jsr     _apu_write_4015  ; APU/IO write
    moveq   #15,D0
    jsr     _apu_write_4015  ; APU/IO write
    bne  _L_z00_DriveAudio_Paused
    even
_L_z00_DriveAudio_Play:
    ; Else the game is not paused.
    ;
    ; Synchronize the APU frame counter once a video frame.
    ;
    move.b  #$FF,D0
    jsr     _apu_write_4017  ; APU/IO write
    ; Drive each game sound channel.
    ;
    jsr     DriveTune1
    jsr     DriveEffect
    jsr     DriveSample
    jsr     DriveSong
    even
_L_z00_DriveAudio_Paused:
    jsr     DriveTune0
    ; Reset all requests for sound.
    ;
    moveq   #0,D0
    move.b  D0,($0604,A4)
    move.b  D0,($0603,A4)
    move.b  D0,($0602,A4)
    move.b  D0,($0601,A4)
    move.b  D0,($0600,A4)
    rts

    even
