_L_z00_ApplySq1Effects_PrepNoteOrPassage:
    moveq   #0,D3
    move.b  ($060C,A4),D3
    addq.b  #1,($060C,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
