_L_z00_ApplySq1Effects_HandleNoise:
    ; If the song is not demo nor ending, then return.
    ; They don't use noise.
    ;
    move.b  ($0609,A4),D0
    andi.b #$91,D0
    beq  _L_z00_ApplySq1Effects_Exit
    subq.b  #1,($0617,A4)
    bne  _L_z00_ApplySq1Effects_Exit
_anon_z00_21:
    moveq   #0,D3
    move.b  ($060D,A4),D3
    addq.b  #1,($060D,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
